  Future<Failure> _getEmailVerificationStatus({
    required String email,
    required String password,
  }) async {
    final methodFc = _fc.category('GVS');

    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'GET',
      path:
          '/auth/users/verification-status?email=${Uri.encodeQueryComponent(email)}',
      responseMapper: EmailVerificationStatusResponse.fromJson,
      authenticated: false,
    );
    if (result.hasLeft) {
      return result.left;
    }

    final status = result.right.status;
    switch (status) {
      case EmailVerificationStatus.notVerified:
        // メール未検証の場合
        // この場合には localStorage に保存されている email, password, birthday の情報が
        // このユーザーのものでない可能性があるため上書きする
